const fs = require('fs-extra');
const path = require('path');

module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 1,
version: '1.0.0',
    name: 'logout',
    aliases: ['signout'],
    description: 'Logout bot from Facebook',
    usage: 'logout',
    category: 'Admin',
    adminOnly: true,
    prefix: true
  },
  
  async run({ api, event, send, config }) {
    const { senderID } = event;
    
    await send.reply(`━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n🅛𝐨𝐠𝐠𝐢𝐧𝐠 𝐨𝐮𝐭 ${config.BOTNAME}...\n\n🅑𝐨𝐭 𝐰𝐢𝐥𝐥 𝐛𝐞 𝐨𝐟𝐟𝐥𝐢𝐧𝐞 𝐮𝐧𝐭𝐢𝐥 𝐫𝐞𝐬𝐭𝐚𝐫𝐭𝐞𝐝.\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━`);
    
    try {
      await api.logout();
      
      const appstatePath = path.join(__dirname, '../../Data/appstate.json');
      if (fs.existsSync(appstatePath)) {
        fs.unlinkSync(appstatePath);
      }
      
      console.log('Bot logged out successfully');
    } catch (error) {
      console.error('Logout error:', error.message);
    }
  }
};
